arguments.prompt:
You are implementing a Blazor Web App for a veterinary clinic. The project is already scaffolded at `/tmp/sv-69bfc8eeb25742519002e8c710ef0134/VetClinic` with:
- .NET 11.0 preview, Interactive Server global mode with Individual auth
- SQLite database with EF Core Identity already configured
- The template has Counter.razor, Weather.razor, Auth.razor demo pages that need to be removed

## What to build

### 1. Domain Models (create in `Data/` folder)

Create these model classes:

**Owner.cs**
```csharp
namespace VetClinic.Data;

public class Owner
{
    public int Id { get; set; }
    public string FirstName { get; set; } = string.Empty;
    public string LastName { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public List<Pet> Pets { get; set; } = new();
}
```

**Pet.cs**
```csharp
namespace VetClinic.Data;

public class Pet
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Species { get; set; } = string.Empty; // Dog, Cat, Bird, etc.
    public string Breed { get; set; } = string.Empty;
    public DateTime DateOfBirth { get; set; }
    public decimal Weight { get; set; }
    public int OwnerId { get; set; }
    public Owner Owner { get; set; } = null!;
    public List<TreatmentNote> TreatmentNotes { get; set; } = new();
    public List<Appointment> Appointments { get; set; } = new();
}
```

**TreatmentNote.cs**
```csharp
namespace VetClinic.Data;

public class TreatmentNote
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime Date { get; set; }
    public string Diagnosis { get; set; } = string.Empty;
    public string Treatment { get; set; } = string.Empty;
    public string Medications { get; set; } = string.Empty;
    public string Notes { get; set; } = string.Empty;
    public string VeterinarianName { get; set; } = string.Empty;
}
```

**Appointment.cs**
```csharp
namespace VetClinic.Data;

public class Appointment
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime StartTime { get; set; }
    public DateTime EndTime { get; set; }
    public string Reason { get; set; } = string.Empty;
    public AppointmentStatus Status { get; set; } = AppointmentStatus.Scheduled;
    public string Notes { get; set; } = string.Empty;
}

public enum AppointmentStatus
{
    Scheduled,
    Completed,
    Cancelled
}
```

**Invoice.cs**
```csharp
namespace VetClinic.Data;

public class Invoice
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime IssuedDate { get; set; }
    public DateTime? DueDate { get; set; }
    public string Description { get; set; } = string.Empty;
    public decimal Amount { get; set; }
    public decimal AmountPaid { get; set; }
    public InvoiceStatus Status { get; set; } = InvoiceStatus.Unpaid;
    public List<Payment> Payments { get; set; } = new();
}

public enum InvoiceStatus
{
    Unpaid,
    PartiallyPaid,
    Paid
}
```

**Payment.cs**
```csharp
namespace VetClinic.Data;

public class Payment
{
    public int Id { get; set; }
    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
    public decimal Amount { get; set; }
    public DateTime PaidDate { get; set; }
    public string Method { get; set; } = string.Empty; // Cash, Card, Check
    public string Reference { get; set; } = string.Empty;
}
```

### 2. Update ApplicationDbContext

Add DbSets for all entities and configure relationships in OnModelCreating:

```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<TreatmentNote> TreatmentNotes => Set<TreatmentNote>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Owner>(e =>
        {
            e.HasMany(o => o.Pets).WithOne(p => p.Owner).HasForeignKey(p => p.OwnerId);
        });

        builder.Entity<Pet>(e =>
        {
            e.HasMany(p => p.TreatmentNotes).WithOne(t => t.Pet).HasForeignKey(t => t.PetId);
            e.HasMany(p => p.Appointments).WithOne(a => a.Pet).HasForeignKey(a => a.PetId);
        });

        builder.Entity<Invoice>(e =>
        {
            e.HasOne(i => i.Pet).WithMany().HasForeignKey(i => i.PetId);
            e.HasMany(i => i.Payments).WithOne(p => p.Invoice).HasForeignKey(p => p.InvoiceId);
            e.Property(i => i.Amount).HasColumnType("decimal(18,2)");
            e.Property(i => i.AmountPaid).HasColumnType("decimal(18,2)");
        });

        builder.Entity<Payment>(e =>
        {
            e.Property(p => p.Amount).HasColumnType("decimal(18,2)");
        });

        builder.Entity<Pet>(e =>
        {
            e.Property(p => p.Weight).HasColumnType("decimal(18,2)");
        });
    }
}
```

### 3. Create a ClinicService (create `Services/ClinicService.cs`)

This service handles all data operations. Register it as Scoped in Program.cs.

```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class ClinicService(ApplicationDbContext db)
{
    // --- Owners ---
    public async Task<List<Owner>> GetOwnersAsync() =>
        await db.Owners.Include(o => o.Pets).OrderBy(o => o.LastName).ToListAsync();

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);

    public async Task SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0) db.Owners.Add(owner);
        else db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    // --- Pets ---
    public async Task<List<Pet>> GetPetsAsync() =>
        await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();

    public async Task<Pet?> GetPetAsync(int id) =>
        await db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.StartTime))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task SavePetAsync(Pet pet)
    {
        if (pet.Id == 0) db.Pets.Add(pet);
        else db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task<List<Pet>> SearchPetsAsync(string query) =>
        await db.Pets.Include(p => p.Owner)
            .Where(p => p.Name.Contains(query) || p.Owner.LastName.Contains(query))
            .OrderBy(p => p.Name).ToListAsync();

    // --- Treatment Notes ---
    public async Task SaveTreatmentNoteAsync(TreatmentNote note)
    {
        if (note.Id == 0) db.TreatmentNotes.Add(note);
        else db.TreatmentNotes.Update(note);
        await db.SaveChangesAsync();
    }

    // --- Appointments ---
    public async Task<List<Appointment>> GetAppointmentsForDateAsync(DateTime date) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime).ToListAsync();

    public async Task<List<Appointment>> GetAppointmentsForWeekAsync(DateTime weekStart) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekStart.AddDays(7))
            .OrderBy(a => a.StartTime).ToListAsync();

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        if (appointment.Id == 0) db.Appointments.Add(appointment);
        else db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<bool> IsTimeSlotAvailableAsync(DateTime start, DateTime end, int? excludeAppointmentId = null) =>
        !await db.Appointments.AnyAsync(a =>
            a.Id != (excludeAppointmentId ?? 0) &&
            a.Status != AppointmentStatus.Cancelled &&
            a.StartTime < end && a.EndTime > start);

    // --- Invoices ---
    public async Task<List<Invoice>> GetInvoicesAsync() =>
        await db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate).ToListAsync();

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments.OrderByDescending(p => p.PaidDate))
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0) db.Invoices.Add(invoice);
        else db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    // --- Payments ---
    public async Task AddPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        var invoice = await db.Invoices.FindAsync(payment.InvoiceId);
        if (invoice != null)
        {
            invoice.AmountPaid += payment.Amount;
            invoice.Status = invoice.AmountPaid >= invoice.Amount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        }
        await db.SaveChangesAsync();
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync() =>
        await db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaidDate).ToListAsync();
}
```

### 4. Update Program.cs

Add `builder.Services.AddScoped<VetClinic.Services.ClinicService>();` right after the Identity service registrations. Also add `builder.Services.AddAuthorization(options => { options.FallbackPolicy = options.DefaultPolicy; });` to require auth on all pages (except Account pages which use `[AllowAnonymous]`).

### 5. Delete template demo pages

Delete these files:
