    protected override async Task OnInitializedAsync()
    {
        pets = await Clinic.GetPetsAsync();
    }

    private async Task SearchAsync()
    {
        pets = string.IsNullOrWhiteSpace(searchQuery)
            ? await Clinic.GetPetsAsync()
            : await Clinic.SearchPetsAsync(searchQuery);
    }

    private void ShowRegisterForm()
    {
        editingOwner = new Owner();
        editingPet = new Pet { DateOfBirth = DateTime.Today };
        showForm = true;
