        await Clinic.SaveOwnerAsync(editingOwner);
        editingPet.OwnerId = editingOwner.Id;
        await Clinic.SavePetAsync(editingPet);

        showForm = false;
        pets = await Clinic.GetPetsAsync();
    }

    private async Task SelectPetAsync(int petId)
    {
        selectedPet = await Clinic.GetPetAsync(petId);
    }

    private void ShowAddNote()
    {
        newNote = new TreatmentNote { PetId = selectedPet!.Id, Date = DateTime.Today };
        showNoteForm = true;
