        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-success" @onclick="ShowNewInvoice">+ Create Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-3">
            <div class="card-header">
                <strong>New Invoice</strong>
                <button class="btn btn-sm btn-outline-secondary float-end" @onclick="() => showInvoiceForm = false">Cancel</button>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Patient</label>
                        <select class="form-select" @bind="newInvoice!.PetId">
                            <option value="0">Select patient...</option>
                            @if (allPets != null)
                            {
                                @foreach (var pet in allPets)
                                {
                                    <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                                }
                            }
                        </select>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Description</label>
                        <input class="form-control" @bind="newInvoice!.Description" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Amount</label>
                        <input class="form-control" type="number" step="0.01" @bind="newInvoice!.Amount" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Due Date</label>
                        <input class="form-control" type="date" @bind="newInvoice!.DueDate" />
                    </div>
                </div>
                <button class="btn btn-success" @onclick="SaveInvoiceAsync">Create Invoice</button>
            </div>
        </div>
    }

    @if (invoices != null)
    {
        <table class="table table-hover">
            <thead>
                <tr>
                    <th>#</th>
                    <th>Patient</th>
                    <th>Description</th>
                    <th>Amount</th>
                    <th>Paid</th>
                    <th>Status</th>
                    <th>Actions</th>
