using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class ClinicService(ApplicationDbContext db)
{
    // --- Owners ---
    public async Task<List<Owner>> GetOwnersAsync() =>
        await db.Owners.Include(o => o.Pets).OrderBy(o => o.LastName).ToListAsync();

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);

    public async Task SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0) db.Owners.Add(owner);
        else db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    // --- Pets ---
    public async Task<List<Pet>> GetPetsAsync() =>
        await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();

    public async Task<Pet?> GetPetAsync(int id) =>
        await db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.StartTime))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task SavePetAsync(Pet pet)
    {
        if (pet.Id == 0) db.Pets.Add(pet);
        else db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task<List<Pet>> SearchPetsAsync(string query) =>
        await db.Pets.Include(p => p.Owner)
            .Where(p => p.Name.Contains(query) || p.Owner.LastName.Contains(query))
            .OrderBy(p => p.Name).ToListAsync();

    // --- Treatment Notes ---
    public async Task SaveTreatmentNoteAsync(TreatmentNote note)
    {
        if (note.Id == 0) db.TreatmentNotes.Add(note);
        else db.TreatmentNotes.Update(note);
        await db.SaveChangesAsync();
    }

    // --- Appointments ---
    public async Task<List<Appointment>> GetAppointmentsForDateAsync(DateTime date) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime).ToListAsync();

    public async Task<List<Appointment>> GetAppointmentsForWeekAsync(DateTime weekStart) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekStart.AddDays(7))
            .OrderBy(a => a.StartTime).ToListAsync();

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        if (appointment.Id == 0) db.Appointments.Add(appointment);
        else db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<bool> IsTimeSlotAvailableAsync(DateTime start, DateTime end, int? excludeAppointmentId = null) =>
        !await db.Appointments.AnyAsync(a =>
            a.Id != (excludeAppointmentId ?? 0) &&
            a.Status != AppointmentStatus.Cancelled &&
            a.StartTime < end && a.EndTime > start);

    // --- Invoices ---
    public async Task<List<Invoice>> GetInvoicesAsync() =>
        await db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate).ToListAsync();

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments.OrderByDescending(p => p.PaidDate))
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0) db.Invoices.Add(invoice);
        else db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    // --- Payments ---
    public async Task AddPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        var invoice = await db.Invoices.FindAsync(payment.InvoiceId);
        if (invoice != null)
        {
            invoice.AmountPaid += payment.Amount;
            invoice.Status = invoice.AmountPaid >= invoice.Amount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        }
        await db.SaveChangesAsync();
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync() =>
        await db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaidDate).ToListAsync();
}

