@page "/"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data
@using VetClinic.Services
@attribute [Authorize]
@inject ClinicService Clinic

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="row">
    <div class="col-md-4">
        <div class="card mb-3">
            <div class="card-header"><strong>Today's Appointments</strong></div>
            <div class="card-body">
                @if (todayAppointments == null)
                {
                    <p><em>Loading...</em></p>
                }
                else if (!todayAppointments.Any())
                {
                    <p class="text-muted">No appointments today.</p>
                }
                else
                {
                    <ul class="list-group list-group-flush">
                        @foreach (var appt in todayAppointments)
                        {
                            <li class="list-group-item d-flex justify-content-between">
                                <span>@appt.StartTime.ToString("HH:mm") - @appt.Pet.Name</span>
                                <span class="badge bg-info">@appt.Reason</span>
                            </li>
                        }
                    </ul>
                }
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card mb-3">
            <div class="card-header"><strong>Quick Actions</strong></div>
            <div class="card-body">
                <a href="/patients" class="btn btn-primary d-block mb-2">Register New Patient</a>
                <a href="/appointments" class="btn btn-success d-block mb-2">Schedule Appointment</a>
                <a href="/billing" class="btn btn-warning d-block mb-2">Create Invoice</a>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card mb-3">
            <div class="card-header"><strong>Unpaid Invoices</strong></div>
            <div class="card-body">
                @if (unpaidInvoices == null)
                {
                    <p><em>Loading...</em></p>
                }
                else if (!unpaidInvoices.Any())
                {
                    <p class="text-muted">All invoices paid!</p>
                }
                else
                {
                    <ul class="list-group list-group-flush">
                        @foreach (var inv in unpaidInvoices.Take(5))
                        {
                            <li class="list-group-item d-flex justify-content-between">
                                <span>@inv.Pet.Name - @inv.Description</span>
                                <span class="text-danger">@((inv.Amount - inv.AmountPaid).ToString("C"))</span>
                            </li>
                        }
                    </ul>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private List<Appointment>? todayAppointments;
    private List<Invoice>? unpaidInvoices;

    protected override async Task OnInitializedAsync()
    {
        todayAppointments = await Clinic.GetAppointmentsForDateAsync(DateTime.Today);
        unpaidInvoices = (await Clinic.GetInvoicesAsync()).Where(i => i.Status != InvoiceStatus.Paid).ToList();
    }
}

