@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data
@using VetClinic.Services
@attribute [Authorize]
@inject ClinicService Clinic

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Search by pet name or owner..." @bind="searchQuery" @bind:event="oninput" @onkeyup="SearchAsync" />
            <button class="btn btn-outline-secondary" @onclick="SearchAsync">Search</button>
        </div>
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowRegisterForm">+ Register New Patient</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">
            <strong>@(editingPet?.Id > 0 ? "Edit Patient" : "Register New Patient")</strong>
            <button class="btn btn-sm btn-outline-secondary float-end" @onclick="CancelForm">Cancel</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <h5>Owner Information</h5>
                    <div class="mb-2">
                        <label class="form-label">First Name</label>
                        <input class="form-control" @bind="editingOwner!.FirstName" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Last Name</label>
                        <input class="form-control" @bind="editingOwner!.LastName" />
                    </div>
                    <div class="mb-2">
