    private bool showInvoiceForm;
    private bool showPaymentForm;

    protected override async Task OnInitializedAsync()
    {
        allPets = await Clinic.GetPetsAsync();
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        invoices = await Clinic.GetInvoicesAsync();
        payments = await Clinic.GetPaymentHistoryAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoice = new Invoice { IssuedDate = DateTime.Today, DueDate = DateTime.Today.AddDays(30) };
        showInvoiceForm = true;
    }

    private async Task SaveInvoiceAsync()
    {
        if (newInvoice == null || newInvoice.PetId == 0) return;
        await Clinic.SaveInvoiceAsync(newInvoice);
        showInvoiceForm = false;
        await LoadDataAsync();
    }

    private void ShowPaymentForm(Invoice invoice)
    {
        paymentInvoice = invoice;
        newPayment = new Payment
        {
            InvoiceId = invoice.Id,
            Amount = invoice.Amount - invoice.AmountPaid,
            PaidDate = DateTime.Today,
            Method = "Cash"
        };
        showPaymentForm = true;
    }

    private async Task ProcessPaymentAsync()
    {
        if (newPayment == null) return;
        await Clinic.AddPaymentAsync(newPayment);
        showPaymentForm = false;
        await LoadDataAsync();
    }

    private async Task ViewInvoice(Invoice inv)
    {
        selectedInvoice = await Clinic.GetInvoiceAsync(inv.Id);
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.PartiallyPaid => "bg-warning text-dark",
        _ => "bg-danger"
    };
}

