@code {
    private List<Pet>? pets;
    private Pet? selectedPet;
    private Pet? editingPet;
    private Owner? editingOwner;
    private bool showForm;
    private bool showNoteForm;
    private TreatmentNote? newNote;
    private string searchQuery = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        pets = await Clinic.GetPetsAsync();
    }

    private async Task SearchAsync()
    {
        pets = string.IsNullOrWhiteSpace(searchQuery)
            ? await Clinic.GetPetsAsync()
            : await Clinic.SearchPetsAsync(searchQuery);
    }

    private void ShowRegisterForm()
    {
        editingOwner = new Owner();
        editingPet = new Pet { DateOfBirth = DateTime.Today };
        showForm = true;
    }

    private void EditPatient(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species, Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth, Weight = pet.Weight, OwnerId = pet.OwnerId
        };
        editingOwner = new Owner
        {
            Id = pet.Owner.Id, FirstName = pet.Owner.FirstName, LastName = pet.Owner.LastName,
            Phone = pet.Owner.Phone, Email = pet.Owner.Email
        };
        showForm = true;
    }

    private void CancelForm()
    {
        showForm = false;
        editingPet = null;
        editingOwner = null;
    }

    private async Task SavePatientAsync()
    {
        if (editingOwner == null || editingPet == null) return;

        await Clinic.SaveOwnerAsync(editingOwner);
        editingPet.OwnerId = editingOwner.Id;
        await Clinic.SavePetAsync(editingPet);

        showForm = false;
        pets = await Clinic.GetPetsAsync();
    }

    private async Task SelectPetAsync(int petId)
    {
        selectedPet = await Clinic.GetPetAsync(petId);
    }

    private void ShowAddNote()
    {
        newNote = new TreatmentNote { PetId = selectedPet!.Id, Date = DateTime.Today };
        showNoteForm = true;
