    private async Task SaveNoteAsync()
    {
        if (newNote == null) return;
        await Clinic.SaveTreatmentNoteAsync(newNote);
        showNoteForm = false;
        selectedPet = await Clinic.GetPetAsync(selectedPet!.Id);
    }
}

@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data
@using VetClinic.Services
@attribute [Authorize]
@inject ClinicService Clinic

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <div class="input-group">
            <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Prev</button>
            <input type="date" class="form-control" @bind="currentDate" @bind:event="onchange" @bind:after="LoadAppointmentsAsync" />
            <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
            <button class="btn btn-outline-primary" @onclick="GoToToday">Today</button>
        </div>
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-success" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">
            <strong>@(editingAppointment?.Id > 0 ? "Edit Appointment" : "New Appointment")</strong>
            <button class="btn btn-sm btn-outline-secondary float-end" @onclick="CancelForm">Cancel</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-4 mb-2">
                    <label class="form-label">Patient</label>
                    <select class="form-select" @bind="editingAppointment!.PetId">
                        <option value="0">Select patient...</option>
                        @if (allPets != null)
                        {
                            @foreach (var pet in allPets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                            }
                        }
                    </select>
                </div>
                <div class="col-md-3 mb-2">
                    <label class="form-label">Date &amp; Time</label>
                    <input class="form-control" type="datetime-local" @bind="editingAppointment!.StartTime" @bind:after="CheckAvailabilityAsync" />
                </div>
                <div class="col-md-2 mb-2">
                    <label class="form-label">Duration (min)</label>
                    <select class="form-select" @bind="appointmentDuration" @bind:after="CheckAvailabilityAsync">
                        <option value="15">15</option>
                        <option value="30">30</option>
                        <option value="45">45</option>
                        <option value="60">60</option>
                    </select>
                </div>
                <div class="col-md-3 mb-2">
                    <label class="form-label">Reason</label>
                    <input class="form-control" @bind="editingAppointment!.Reason" />
                </div>
            </div>
            <div class="mb-2">
                <label class="form-label">Notes</label>
                <textarea class="form-control" rows="2" @bind="editingAppointment!.Notes"></textarea>
            </div>

            @if (availabilityChecked)
            {
                @if (isSlotAvailable)
                {
                    <div class="alert alert-success py-1">✓ Time slot is available</div>
                }
                else
                {
                    <div class="alert alert-danger py-1">✗ Time slot conflicts with another appointment</div>
                }
            }

            <button class="btn btn-success" @onclick="SaveAppointmentAsync" disabled="@(!isSlotAvailable && availabilityChecked)">Save</button>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="@(day.Date == DateTime.Today ? "table-info" : "")">@day.ToString("ddd MM/dd")</th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-muted small">@($"{hour:00}:00")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var slotStart = day.AddHours(hour);
                        var slotAppts = weekAppointments?.Where(a => a.StartTime >= slotStart && a.StartTime < slotStart.AddHours(1) && a.Status != AppointmentStatus.Cancelled).ToList();
                        <td class="small">
                            @if (slotAppts?.Any() == true)
                            {
                                @foreach (var appt in slotAppts)
                                {
                                    <div class="badge bg-primary d-block mb-1 text-start" style="cursor:pointer" @onclick="() => EditAppointment(appt)">
                                        @appt.StartTime.ToString("HH:mm") @appt.Pet.Name<br/>
                                        <small>@appt.Reason</small>
                                    </div>
                                }
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@if (selectedAppointment != null)
{
    <div class="card mt-3">
        <div class="card-header d-flex justify-content-between">
            <strong>Appointment Details</strong>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => selectedAppointment = null">Close</button>
        </div>
        <div class="card-body">
            <p><strong>Patient:</strong> @selectedAppointment.Pet.Name (@selectedAppointment.Pet.Owner.LastName)</p>
            <p><strong>Time:</strong> @selectedAppointment.StartTime.ToString("g") - @selectedAppointment.EndTime.ToString("t")</p>
            <p><strong>Reason:</strong> @selectedAppointment.Reason</p>
            <p><strong>Status:</strong> @selectedAppointment.Status</p>
            @if (!string.IsNullOrWhiteSpace(selectedAppointment.Notes))
            {
                <p><strong>Notes:</strong> @selectedAppointment.Notes</p>
            }
            <button class="btn btn-warning btn-sm" @onclick="() => RescheduleAppointment(selectedAppointment)">Reschedule</button>
            <button class="btn btn-danger btn-sm" @onclick="() => CancelAppointmentAsync(selectedAppointment.Id)">Cancel</button>
        </div>
    </div>
}

@code {
    private DateTime currentDate = DateTime.Today;
    private DateTime weekStart;
    private List<Appointment>? weekAppointments;
    private List<Pet>? allPets;
    private Appointment? editingAppointment;
    private Appointment? selectedAppointment;
    private bool showForm;
    private int appointmentDuration = 30;
    private bool availabilityChecked;
    private bool isSlotAvailable;

    protected override async Task OnInitializedAsync()
    {
        weekStart = currentDate.AddDays(-(int)currentDate.DayOfWeek);
        allPets = await Clinic.GetPetsAsync();
        await LoadAppointmentsAsync();
    }

    private async Task LoadAppointmentsAsync()
    {
        weekStart = currentDate.AddDays(-(int)currentDate.DayOfWeek);
        weekAppointments = await Clinic.GetAppointmentsForWeekAsync(weekStart);
    }

    private void PreviousWeek() { currentDate = currentDate.AddDays(-7); _ = LoadAppointmentsAsync(); }
    private void NextWeek() { currentDate = currentDate.AddDays(7); _ = LoadAppointmentsAsync(); }
    private void GoToToday() { currentDate = DateTime.Today; _ = LoadAppointmentsAsync(); }

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment { StartTime = DateTime.Today.AddHours(9) };
        appointmentDuration = 30;
        availabilityChecked = false;
        showForm = true;
        selectedAppointment = null;
    }

    private void EditAppointment(Appointment appt)
    {
        selectedAppointment = appt;
    }

    private void RescheduleAppointment(Appointment appt)
    {
        editingAppointment = new Appointment
        {
            Id = appt.Id, PetId = appt.PetId, StartTime = appt.StartTime,
            EndTime = appt.EndTime, Reason = appt.Reason, Notes = appt.Notes, Status = appt.Status
        };
        appointmentDuration = (int)(appt.EndTime - appt.StartTime).TotalMinutes;
        availabilityChecked = false;
        showForm = true;
        selectedAppointment = null;
    }

    private void CancelForm()
    {
        showForm = false;
        editingAppointment = null;
    }

    private async Task CheckAvailabilityAsync()
    {
        if (editingAppointment == null) return;
        var end = editingAppointment.StartTime.AddMinutes(appointmentDuration);
        isSlotAvailable = await Clinic.IsTimeSlotAvailableAsync(editingAppointment.StartTime, end, editingAppointment.Id > 0 ? editingAppointment.Id : null);
        availabilityChecked = true;
    }

    private async Task SaveAppointmentAsync()
    {
        if (editingAppointment == null || editingAppointment.PetId == 0) return;
        editingAppointment.EndTime = editingAppointment.StartTime.AddMinutes(appointmentDuration);
        await Clinic.SaveAppointmentAsync(editingAppointment);
        showForm = false;
        await LoadAppointmentsAsync();
    }

    private async Task CancelAppointmentAsync(int id)
    {
        await Clinic.CancelAppointmentAsync(id);
        selectedAppointment = null;
        await LoadAppointmentsAsync();
    }
}

@page "/billing"
