    }

    @if (invoices != null)
    {
        <table class="table table-hover">
            <thead>
                <tr>
                    <th>#</th>
                    <th>Patient</th>
                    <th>Description</th>
                    <th>Amount</th>
                    <th>Paid</th>
                    <th>Status</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var inv in invoices)
                {
                    <tr>
                        <td>@inv.Id</td>
                        <td>@inv.Pet.Name</td>
                        <td>@inv.Description</td>
                        <td>@inv.Amount.ToString("C")</td>
                        <td>@inv.AmountPaid.ToString("C")</td>
                        <td>
                            <span class="badge @GetStatusBadge(inv.Status)">@inv.Status</span>
                        </td>
                        <td>
                            @if (inv.Status != InvoiceStatus.Paid)
                            {
                                <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPaymentForm(inv)">Record Payment</button>
                            }
                            <button class="btn btn-sm btn-outline-info" @onclick="() => ViewInvoice(inv)">Details</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }

    @if (showPaymentForm && paymentInvoice != null)
    {
        <div class="card mb-3 border-success">
            <div class="card-header bg-success text-white">
                <strong>Record Payment - Invoice #@paymentInvoice.Id (@paymentInvoice.Pet.Name)</strong>
                <button class="btn btn-sm btn-outline-light float-end" @onclick="() => showPaymentForm = false">Cancel</button>
            </div>
            <div class="card-body">
                <p>Outstanding: <strong>@((paymentInvoice.Amount - paymentInvoice.AmountPaid).ToString("C"))</strong></p>
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Amount</label>
                        <input class="form-control" type="number" step="0.01" @bind="newPayment!.Amount" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="newPayment!.Method">
                            <option value="Cash">Cash</option>
                            <option value="Card">Card</option>
                            <option value="Check">Check</option>
                        </select>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Reference</label>
                        <input class="form-control" @bind="newPayment!.Reference" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Date</label>
                        <input class="form-control" type="date" @bind="newPayment!.PaidDate" />
                    </div>
                </div>
                <button class="btn btn-success" @onclick="ProcessPaymentAsync">Process Payment</button>
            </div>
        </div>
    }

    @if (selectedInvoice != null)
    {
        <div class="card mt-3">
            <div class="card-header d-flex justify-content-between">
                <strong>Invoice #@selectedInvoice.Id Details</strong>
                <button class="btn btn-sm btn-outline-secondary" @onclick="() => selectedInvoice = null">Close</button>
            </div>
            <div class="card-body">
                <p><strong>Patient:</strong> @selectedInvoice.Pet.Name | <strong>Owner:</strong> @selectedInvoice.Pet.Owner.FirstName @selectedInvoice.Pet.Owner.LastName</p>
                <p><strong>Issued:</strong> @selectedInvoice.IssuedDate.ToString("d") | <strong>Due:</strong> @(selectedInvoice.DueDate?.ToString("d") ?? "N/A")</p>
                <p><strong>Description:</strong> @selectedInvoice.Description</p>
                <p><strong>Total:</strong> @selectedInvoice.Amount.ToString("C") | <strong>Paid:</strong> @selectedInvoice.AmountPaid.ToString("C")</p>

                @if (selectedInvoice.Payments.Any())
                {
                    <h6 class="mt-3">Payments</h6>
                    <table class="table table-sm">
                        <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                        <tbody>
                            @foreach (var p in selectedInvoice.Payments)
                            {
                                <tr><td>@p.PaidDate.ToString("d")</td><td>@p.Amount.ToString("C")</td><td>@p.Method</td><td>@p.Reference</td></tr>
                            }
                        </tbody>
                    </table>
                }
            </div>
        </div>
    }
}
else
{
    <h5>Payment History</h5>
    @if (payments != null)
    {
        <table class="table">
            <thead>
                <tr><th>Date</th><th>Invoice #</th><th>Patient</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
            </thead>
            <tbody>
                @foreach (var p in payments)
                {
                    <tr>
                        <td>@p.PaidDate.ToString("d")</td>
                        <td>@p.InvoiceId</td>
                        <td>@p.Invoice.Pet.Name</td>
                        <td>@p.Amount.ToString("C")</td>
                        <td>@p.Method</td>
                        <td>@p.Reference</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    private string activeTab = "invoices";
    private List<Invoice>? invoices;
    private List<Payment>? payments;
    private List<Pet>? allPets;
    private Invoice? newInvoice;
    private Invoice? selectedInvoice;
    private Invoice? paymentInvoice;
    private Payment? newPayment;
    private bool showInvoiceForm;
    private bool showPaymentForm;

    protected override async Task OnInitializedAsync()
    {
        allPets = await Clinic.GetPetsAsync();
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        invoices = await Clinic.GetInvoicesAsync();
        payments = await Clinic.GetPaymentHistoryAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoice = new Invoice { IssuedDate = DateTime.Today, DueDate = DateTime.Today.AddDays(30) };
        showInvoiceForm = true;
    }

    private async Task SaveInvoiceAsync()
    {
        if (newInvoice == null || newInvoice.PetId == 0) return;
        await Clinic.SaveInvoiceAsync(newInvoice);
        showInvoiceForm = false;
        await LoadDataAsync();
    }

    private void ShowPaymentForm(Invoice invoice)
    {
        paymentInvoice = invoice;
        newPayment = new Payment
        {
            InvoiceId = invoice.Id,
            Amount = invoice.Amount - invoice.AmountPaid,
            PaidDate = DateTime.Today,
            Method = "Cash"
        };
        showPaymentForm = true;
    }

    private async Task ProcessPaymentAsync()
    {
        if (newPayment == null) return;
        await Clinic.AddPaymentAsync(newPayment);
        showPaymentForm = false;
        await LoadDataAsync();
    }

    private async Task ViewInvoice(Invoice inv)
    {
        selectedInvoice = await Clinic.GetInvoiceAsync(inv.Id);
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.PartiallyPaid => "bg-warning text-dark",
        _ => "bg-danger"
    };
}
